diff --git a/test/calc.test.ts b/test/calc.test.ts
new file mode 100644
--- /dev/null
+++ b/test/calc.test.ts
@@ -0,0 +1,7 @@
+import { add, subtract, multiply, divide } from '../src/calc.ts';
+const fail = (msg: string) => { console.error('FAIL:', msg); process.exit(1); };
+if (add(2, 3) !== 5) fail('add(2,3) !== 5');
+if (subtract(5, 3) !== 2) fail('subtract(5,3) !== 2');
+if (multiply(3, 4) !== 12) fail('multiply(3,4) !== 12');
+if (divide(10, 2) !== 5) fail('divide(10,2) !== 5');
+console.log('all assertions passed');
